/**
 * MedX reset forms runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Form reset and dirty-state tracking.
 */
const RESET_TOKENS = Object.freeze({
  primary: { value: "forms-reset-primary", scope: "forms" },
  secondary: { value: "forms-reset-secondary", scope: "forms" },
  muted: { value: "forms-reset-muted", scope: "forms" },
  accent: { value: "forms-reset-accent", scope: "forms" },
  surface: { value: "forms-reset-surface", scope: "forms" },
});

const RESET_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const RESET_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const resetRegistry = new Map();
const RESET_listeners = new Set();
let RESET_seq = 0;

function createResetId(prefix = "medx-forms-reset") {
  RESET_seq += 1;
  return `${prefix}-${RESET_seq}`;
}

function registerReset(config = {}) {
  const entryId = config.id ?? createResetId();
  const preset = RESET_PRESETS[config.preset ?? "default"] ?? RESET_PRESETS.default;
  const token = RESET_TOKENS[config.token ?? preset.token] ?? RESET_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: RESET_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  resetRegistry.set(entryId, entry);
  notifyResetListeners("register", entry);
  return entry;
}

function updateReset(id, patch = {}) {
  const entry = resetRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyResetListeners("update", entry);
  return entry;
}

function resolveReset(id) {
  const entry = resetRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listResetEntries(filter = {}) {
  let items = Array.from(resetRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onResetEvent(listener) {
  RESET_listeners.add(listener);
  return () => RESET_listeners.delete(listener);
}

function notifyResetListeners(type, entry) {
  for (const listener of RESET_listeners) {
    try {
      listener({ type, entry, registrySize: resetRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:forms:reset] listener error", err.message);
    }
  }
}

function getResetMetrics() {
  const items = listResetEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(RESET_TOKENS).length,
    presets: Object.keys(RESET_PRESETS).length,
  };
}

async function runMedxReset() {
  console.log("[medx:ui:forms:reset] runtime initialized");
  console.log(`[medx:ui:forms:reset] tokens=${Object.keys(RESET_TOKENS).length} presets=${Object.keys(RESET_PRESETS).length}`);

  const events = [];
  onResetEvent((e) => events.push(e.type));

  const domains = Object.keys(RESET_SUPPLY_CHAIN);
  const presets = Object.keys(RESET_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerReset({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "forms/reset" },
    });
  }

  const first = listResetEntries()[0];
  if (first) updateReset(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getResetMetrics();
  const resolved = first ? resolveReset(first.id) : null;

  console.log(`[medx:ui:forms:reset] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:forms:reset] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:forms:reset] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:forms:reset] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:forms:reset] bootstrap complete");
}

module.exports = runMedxReset;
